package br.edu.atitus.mathias_karling_stadtlober.zoo_digital.animais; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.comportamentos.*; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.especies.Mamifero; public class Leao extends Mamifero implements Corrida, Predacao { public Leao(String nome, int idade) { super(nome, idade); } public void emitirSom() { System.out.println(getNome() + " ruge alto."); } public void comer() { System.out.println(getNome() + " está comendo carne."); } public void correr() { System.out.println(getNome() + " está correndo na savana."); } public void cacar() { System.out.println(getNome() + " está caçando em bando."); } }
